* Coded by Creative Tim

=========================================================

* The above copyright notice and this permission notice shall be included in all copies or substantial portions of the Software.

*/
import{ CustomInput, Modal, ModalHeader, ModalBody, ModalFooter } from 'reactstrap';
import  { useEffect} from "react";
import * as utils from "views/Dashboard/utils.js";
// core components
import EmojiPicker from 'emoji-picker-react';
import IndexNavbar from "components/Navbars/IndexNavbar.js";
import PageHeader from "components/PageHeader/PageHeader.js";
import Footer from "components/Footer/Footer.js";
import { FiRepeat, FiShuffle, FiPauseCircle, FiSkipForward, FiSkipBack } from 'react-icons/fi';
import { Link, useLocation, BrowserRouter as Router } from "react-router-dom";
// sections for this page/view
import Basics from "views/IndexSections/Basics.js";
import Navbars from "views/IndexSections/Navbars.js";
import Tabs from "views/IndexSections/Tabs.js";
import Pagination from "views/IndexSections/Pagination.js";
import Notifications from "views/IndexSections/Notifications.js";
import Typography from "views/IndexSections/Typography.js";
import JavaScript from "views/IndexSections/JavaScript.js";
import NucleoIcons from "views/IndexSections/NucleoIcons.js";
import Signup from "views/IndexSections/Signup.js";
import Examples from "views/IndexSections/Examples.js";
import { Redirect } from 'react-router';
import React, { useState, useRef } from 'react';

import Download from "views/IndexSections/Download.js";
import { Picker } from 'emoji-mart';
import ReactDOM from "react-dom";
import { BrowserRouter, Route, Switch } from "react-router-dom";

import SideNav, { Toggle, Nav, NavItem, NavIcon, NavText } from '@trendmicro/react-sidenav';

// Be sure to include styles at some point, probably during your bootstraping
import '@trendmicro/react-sidenav/dist/react-sidenav.css';
// import { Card, CardTitle, CardBody, CardActions } from '@progress/kendo-react-layout';
import Loader from "react-loader-spinner";
import classnames from "classnames";
// reactstrap components

import {
   Form,
   FormText,
  Input,
  Alert,
  InputGroup,
  InputGroupAddon,
  InputGroupText,
  FormGroup,
  Label,
  NavLink,



  PaginationItem,
  PaginationLink,
  Badge,
  Progress,
  TabContent,
  TabPane,
  Button,
  Card,
  CardHeader,
  CardBody,

  CardFooter,
  CardTitle,
  ListGroupItem,
  ListGroup,
  Container,
  CardImg, CardText, CardSubtitle,
  Row,
  Col,
} from "reactstrap";

function useQuery() {
  return new URLSearchParams(useLocation().search);
}
function Music(props) {
  const [music, setMusic]= React.useState({});
  const [disabled, setDisabled]= React.useState(true);
  const [prefix, setPrefix]= React.useState(false);
  const [time, setTime]= React.useState(0);
  const [bar, setBar]= React.useState("");



  const [timer, setTimer] = useState(0)
  const [isActive, setIsActive] = useState(false)
  const [isPaused, setIsPaused] = useState(false)
  const countRef = useRef(null)

  const handleStart = () => {
    if (isActive==true){
      return
    }
    setIsActive(true)
  setIsPaused(true)
  countRef.current = setInterval(() => {
    setTimer((timer) => timer + 1)
  }, 1000)
  }

  const handlePause = () => {
    // Pause button logic here
  }

  const handleResume = () => {
    // Resume button logic here
  }

  const handleReset = () => {
    clearInterval(countRef.current)
  setIsActive(false)
  // setIsPaused(false)
  setTimer(0)
  }
  const formatTimer = () => {
    const getSeconds = `0${(timer % 60)}`.slice(-2)
